// ETAPA 1 - Validacion de entrada IoT
const run_id = `RUN-IOT-${Date.now()}-${Math.random().toString(36).substr(2,6).toUpperCase()}`;
const start_ts = new Date().toISOString();
const body = $input.item.json.body || {};

const errores = [];

// Nivel 1 - Campos obligatorios
const CAMPOS_REQUERIDOS = ['sensor_id', 'temperature', 'humidity', 'co2', 'timestamp'];
for (const campo of CAMPOS_REQUERIDOS) {
  if (body[campo] === undefined || body[campo] === null || body[campo] === '') {
    errores.push(`${campo}: campo requerido`);
  }
}

// Nivel 2 - Tipos de dato
if (body.sensor_id !== undefined && typeof body.sensor_id !== 'string') errores.push('sensor_id: debe ser string');

// Nivel 3 - Rangos fisicamente posibles (ADR-006: -50 a 125°C, IEC 60068)
const temp = parseFloat(body.temperature);
const hum = parseFloat(body.humidity);
const co2 = parseFloat(body.co2);

if (!isNaN(temp) && (temp < -50 || temp > 125)) errores.push(`temperature fuera de rango fisico: ${temp} (rango: -50 a 125°C)`);
if (!isNaN(hum) && (hum < 0 || hum > 100)) errores.push(`humidity fuera de rango fisico: ${hum} (rango: 0-100%)`);
if (!isNaN(co2) && (co2 < 0 || co2 > 5000)) errores.push(`co2 fuera de rango fisico: ${co2} (rango: 0-5000 ppm)`);

// Validacion de drift de timestamp (ADR-007): maximo 5 min en el futuro
if (body.timestamp) {
  const sensorTime = new Date(body.timestamp);
  if (isNaN(sensorTime.getTime())) {
    errores.push('timestamp: formato no es fecha valida (se espera ISO 8601)');
  } else {
    const diffMs = sensorTime - new Date();
    if (diffMs > 5 * 60 * 1000) {
      errores.push(`timestamp en el futuro por ${Math.round(diffMs / 1000)}s (maximo permitido: 300s)`);
    }
  }
}

const valido = errores.length === 0;

// Normalizacion completa (ADR-008) — solo si valido
const lectura = valido ? {
  sensor_id: body.sensor_id.trim(),
  temperature: Math.round(temp * 10) / 10,
  humidity: Math.round(hum * 10) / 10,
  co2: Math.round(co2),
  timestamp: new Date(body.timestamp).toISOString(),
  location: body.location ? body.location.trim().toLowerCase() : null
} : null;

console.log(JSON.stringify({
  run_id, etapa: 'E1_validacion_iot',
  status: valido ? 'ok' : 'fail',
  sensor_id: body.sensor_id || null,
  errores, n_errores: errores.length, start_ts
}));

return [{ json: { run_id, start_ts, valido, errores, lectura } }];
